    if node.node_type == 'NUMBER':
        return node.value
    elif node.node_type == 'VARIABLE':
        return variables[node.value]
    elif node.node_type == 'UNARY_MINUS':
        return -evaluate_node(node.children[0], variables)
    elif node.node_type == 'OPERATOR':
        left_value = evaluate_node(node.children[0], variables)
        right_value = evaluate_node(node.children[1], variables)
        if node.value == '+':
            return left_value + right_value
        elif node.value == '-':
            return left_value - right_value
        elif node.value == '*':
            return left_value * right_value
        elif node.value == '//':
            if right_value == 0:
                raise ZeroDivisionError("Division by zero")
